arguments.script:
const axios = require('axios');

async function main() {
  const url = 'https://mp.weixin.qq.com/s/thJD_O-GYfbMNN-8Q07YgQ';
  const response = await axios.get(url, {
    headers: {
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
      'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
      'Accept-Language': 'zh-CN,zh;q=0.9,en;q=0.8',
    },
    timeout: 30000
  });

  // 提取页面标题
  const titleMatch = response.data.match(/<title>([^<]*)<\/title>/i);
  const title = titleMatch ? titleMatch[1] : '未找到标题';

  // 提取文章内容（微信公众号文章通常将内容放在 rich_media_content 中）
  const contentMatch = response.data.match(/<div[^>]*id="js_content"[^>]*>([\s\S]*?)<\/div>\s*<script/i);
  let content = contentMatch ? contentMatch[1] : '';

  // 清理 HTML 标签
  content = content.replace(/<[^>]+>/g, '');
  content = content.replace(/&nbsp;/g, ' ');
  content = content.replace(/&amp;/g, '&');
  content = content.replace(/&lt;/g, '<');
  content = content.replace(/&gt;/g, '>');
  content = content.replace(/&quot;/g, '"');
  content = content.replace(/\s+/g, ' ');
  content = content.trim();

  // 提取作者和发布时间
  const authorMatch = response.data.match(/var\s+author_name\s*=\s*"([^"]+)"/);
  const author = authorMatch ? authorMatch[1] : '未找到';

  const dateMatch = response.data.match(/var\s+create_time\s*=\s*"(\d+)"/);
  const createTime = dateMatch ? new Date(parseInt(dateMatch[1]) * 1000).toLocaleString('zh-CN') : '未找到';

  console.log('标题:', title);
  console.log('作者:', author);
  console.log('发布时间:', createTime);
  console.log('---内容---');
  console.log(content.substring(0, 5000));
}

main().catch(err => {
  console.error('抓取失败:', err.message);
});
